print(f"Businesses loaded: {len(businesses)}")

# Extract categories from business descriptions
def extract_categories(description):
    """Extract business categories from description text"""
    categories = []

    # Pattern 1: "services in X, Y, and Z."
    if 'services in' in description:
        match = re.search(r'services in ([^.]+)\.', description)
        if match:
            text = match.group(1)
            parts = re.split(r',\s*|\sand\s', text)
            return [p.strip() for p in parts if p.strip()]

    # Pattern 2: "including X, Y, and Z."
    if 'including' in description:
        match = re.search(r'including ([^.]+)\.', description)
        if match:
            text = match.group(1)
            parts = re.split(r',\s*|\sand\s', text)
            return [p.strip() for p in parts if p.strip()]

    # Pattern 3: "destination for X, Y, and Z."
    if 'destination for' in description:
        match = re.search(r'destination for ([^.]+)\.', description)
        if match:
            text = match.group(1)
            parts = re.split(r',\s*|\sand\s', text)
            return [p.strip() for p in parts if p.strip()]

    return []

