business_categories = {}
for business in businesses:
    business_id = business.get('business_id', '')
    if business_id:
        categories = extract_categories(business.get('description', ''))
        if categories:
            business_categories[business_id] = categories

print(f"Businesses with category info: {len(business_categories)}")
for bid, cats in list(business_categories.items())[:2]:
    print(f"  {bid}: {cats}")

# Count reviews by category
category_review_counts = Counter()
reviews_loaded_from_file = 0

# Try to load reviews from file if it's a path
if isinstance(reviews_file_info, str) and ('var_functions.query_db:' not in str(reviews_file_info)):
    # This might be the actual file path
    try:
        with open(reviews_file_info, 'r') as f:
            for line_num, line in enumerate(f, 1):
                if line.strip():
                    review = json.loads(line)
                    user_id = review.get('user_id')
                    business_ref = review.get('business_ref')

                    if user_id and user_id in user_ids and business_ref:
                        reviews_loaded_from_file += 1

                        # Convert business_ref to business_id
                        if business_ref.startswith('businessref_'):
                            business_id = 'businessid_' + business_ref.split('businessref_')[1]

                            # Get categories and count
                            if business_id in business_categories:
                                for category in business_categories[business_id]:
                                    category_review_counts[category] += 1

        print(f"Reviews processed from file: {reviews_loaded_from_file}")

    except Exception as e:
        print(f"Error loading reviews file: {e}")
        # Fallback to sample data
        sample_reviews = locals().get('var_functions.query_db:16', [])
        print(f"Using sample reviews: {len(sample_reviews)}")

        for review in sample_reviews:
            user_id = review.get('user_id')
            business_ref = review.get('business_ref')

            if user_id and user_id in user_ids and business_ref:
                reviews_loaded_from_file += 1

                if business_ref.startswith('businessref_'):
                    business_id = 'businessid_' + business_ref.split('businessref_')[1]

                    if business_id in business_categories:
                        for category in business_categories[business_id]:
                            category_review_counts[category] += 1
else:
    # Use sample data
    sample_reviews = locals().get('var_functions.query_db:16', [])
    print(f"File path not detected, using sample: {len(sample_reviews)}")

    for review in sample_reviews:
        user_id = review.get('user_id')
        business_ref = review.get('business_ref')

        if user_id and user_id in user_ids and business_ref:
            if business_ref.startswith('businessref_'):
                business_id = 'businessid_' + business_ref.split('businessref_')[1]

                if business_id in business_categories:
                    for category in business_categories[business_id]:
                        category_review_counts[category] += 1

print(f"Total category assignments: {sum(category_review_counts.values())}")
print(f"Unique categories reviewed: {len(category_review_counts)}")

# Get top 5 categories
top_5 = category_review_counts.most_common(5)
print(f"Top 5 categories: {top_5}")

# Prepare final result
result = {
    'top_5_business_categories': [
        {'rank': i+1, 'category': cat, 'total_reviews': count}
        for i, (cat, count) in enumerate(top_5)
    ],
    'summary': {
        'total_2016_users_analyzed': len(user_ids),
        'total_reviews_processed': reviews_loaded_from_file,
        'total_category_assignments': sum(category_review_counts.values()),
        'businesses_with_category_data': len(business_categories)
    }
}

print('__RESULT__:')
print(json.dumps(result, indent=2))

